long long calculateMaxProfit(int maxTransactions, vector<int>& stockPrices) {

    int n = stockPrices.size();

    if (n == 0 || maxTransactions == 0)
        return 0;

    // Large K → Unlimited transactions case
    if (maxTransactions >= n / 2) {
        long long profit = 0;
        for (int i = 1; i < n; i++) {
            if (stockPrices[i] > stockPrices[i - 1])
                profit += stockPrices[i] - stockPrices[i - 1];
        }
        return profit;
    }

    vector<long long> buy(maxTransactions + 1, LLONG_MIN);
    vector<long long> sell(maxTransactions + 1, 0);

    for (int price : stockPrices) {

        for (int t = 1; t <= maxTransactions; t++) {

            buy[t] = max(buy[t], sell[t - 1] - price);
            sell[t] = max(sell[t], buy[t] + price);
        }
    }

    return sell[maxTransactions];
}

