long long calculateMaxProfit(int n, int maxTransactions, int* stockPrices) {

    if (n == 0 || maxTransactions == 0)
        return 0;

    // If transactions are very large → behaves like unlimited transactions
    if (maxTransactions >= n / 2) {
        long long profit = 0;
        for (int i = 1; i < n; i++) {
            if (stockPrices[i] > stockPrices[i - 1])
                profit += stockPrices[i] - stockPrices[i - 1];
        }
        return profit;
    }

    long long buy[maxTransactions + 1];
    long long sell[maxTransactions + 1];

    // Initialize
    for (int t = 0; t <= maxTransactions; t++) {
        buy[t] = LLONG_MIN;
        sell[t] = 0;
    }

    for (int i = 0; i < n; i++) {

        for (int t = 1; t <= maxTransactions; t++) {

            // Either keep previous buy OR buy today
            if (sell[t - 1] - stockPrices[i] > buy[t])
                buy[t] = sell[t - 1] - stockPrices[i];

            // Either keep previous sell OR sell today
            if (buy[t] + stockPrices[i] > sell[t])
                sell[t] = buy[t] + stockPrices[i];
        }
    }

    return sell[maxTransactions];
}

