class Codechef {
    public long calculateMaxProfit(int maxTransactions, int[] stockPrices) {
        int n = stockPrices.length;

        // Case 1: Large number of transactions (Greedy)
        if (maxTransactions >= n / 2) {
            long maxProfit = 0;
            for (int i = 1; i < n; i++) {
                if (stockPrices[i] > stockPrices[i - 1]) {
                    maxProfit += (stockPrices[i] - stockPrices[i - 1]);
                }
            }
            return maxProfit;
        }

        // Case 2: Limited transactions (DP)
        long[] buy = new long[maxTransactions + 1];
        long[] sell = new long[maxTransactions + 1];

        // Initialize buy array to very small value (as buying is a cost)
        Arrays.fill(buy, Long.MIN_VALUE);

        for (int price : stockPrices) {
            for (int j = 1; j <= maxTransactions; j++) {
                buy[j] = Math.max(buy[j], sell[j - 1] - price);
                sell[j] = Math.max(sell[j], buy[j] + price);
            }
        }
        return sell[maxTransactions];
    }
}

