function calculateMaxProfit(n, k, prices) {
    // Case 1: Large K (Greedy)
    if (k >= Math.floor(n / 2)) {
        let maxProfit = 0;
        for (let i = 1; i < n; i++) {
            if (prices[i] > prices[i - 1]) {
                maxProfit += (prices[i] - prices[i - 1]);
            }
        }
        return maxProfit;
    }

    // Case 2: Small K (DP)
    // Initialize buy array with very small numbers (effectively -Infinity)
    let buy = new Array(k + 1).fill(Number.MIN_SAFE_INTEGER);
    let sell = new Array(k + 1).fill(0);

    for (let price of prices) {
        for (let j = 1; j <= k; j++) {
            buy[j] = Math.max(buy[j], sell[j - 1] - price);
            sell[j] = Math.max(sell[j], buy[j] + price);
        }
    }

    return sell[k];
}
